class Solution:
    def findDiagonalOrder(self, mat):
        rows = len(mat)
        cols = len(mat[0])
        groups = {}
        for r in range(rows):
            for c in range(cols):
                groups.setdefault(r + c, []).append((r, c))
        res = []
        for s in sorted(groups):
            cells = groups[s]
            if s % 2 == 0:
                cells = cells[::-1]
            for r, c in cells:
                res.append(mat[r][c])
        return res

