class Solution:
    def findDiagonalOrder(self, mat):
        rows = len(mat)
        cols = len(mat[0])
        res = []
        for s in range(rows + cols - 1):
            if s % 2 == 0:
                r = min(s, rows - 1)
                c = s - r
                while r >= 0 and c < cols:
                    res.append(mat[r][c])
                    r -= 1
                    c += 1
            else:
                c = min(s, cols - 1)
                r = s - c
                while c >= 0 and r < rows:
                    res.append(mat[r][c])
                    r += 1
                    c -= 1
        return res

