var findDiagonalOrder = function(mat) {
    const rows = mat.length, cols = mat[0].length;
    const res = [];
    for (let s = 0; s < rows + cols - 1; s++) {
        if (s % 2 === 0) {
            let r = Math.min(s, rows - 1);
            let c = s - r;
            while (r >= 0 && c < cols) {
                res.push(mat[r][c]);
                r--; c++;
            }
        } else {
            let c = Math.min(s, cols - 1);
            let r = s - c;
            while (c >= 0 && r < rows) {
                res.push(mat[r][c]);
                r++; c--;
            }
        }
    }
    return res;
};
